/// Audio format.
enum SDLAudioFormat {
  /// Unspecified audio format
  audioUnknown(0),

  /// Unsigned 8-bit samples
  audioU8(8),

  /// Signed 8-bit samples
  audioS8(32776),

  /// Signed 16-bit samples
  audioS16le(32784),

  /// As above, but big-endian byte order
  audioS16be(36880),

  /// 32-bit integer samples
  audioS32le(32800),

  /// As above, but big-endian byte order
  audioS32be(36896),

  /// 32-bit floating point samples
  audioF32le(33056),

  /// As above, but big-endian byte order
  audioF32be(37152);

  static const audioS16 = audioS16le;
  static const audioS32 = audioS32le;
  static const audioF32 = audioF32le;

  final int value;
  const SDLAudioFormat(this.value);

  static SDLAudioFormat fromValue(int value) => switch (value) {
    0 => audioUnknown,
    8 => audioU8,
    32776 => audioS8,
    32784 => audioS16le,
    36880 => audioS16be,
    32800 => audioS32le,
    36896 => audioS32be,
    33056 => audioF32le,
    37152 => audioF32be,
    _ => throw ArgumentError('Unknown value for SDLAudioFormat: $value'),
  };

  @override
  String toString() {
    if (this == audioS16le)
      return "SDLAudioFormat.audioS16le, SDLAudioFormat.audioS16";
    if (this == audioS32le)
      return "SDLAudioFormat.audioS32le, SDLAudioFormat.audioS32";
    if (this == audioF32le)
      return "SDLAudioFormat.audioF32le, SDLAudioFormat.audioF32";
    return super.toString();
  }
}

