  };
}

final class SDLCursor extends ffi.Opaque {}

/// Cursor types for SDL_CreateSystemCursor().
enum SDLSystemCursor {
  /// Default cursor. Usually an arrow.
  systemCursorDefault(0),

  /// Text selection. Usually an I-beam.
  systemCursorText(1),

  /// Wait. Usually an hourglass or watch or spinning ball.
  systemCursorWait(2),

  /// Crosshair.
  systemCursorCrosshair(3),

  /// Program is busy but still interactive. Usually it's WAIT with an arrow.
  systemCursorProgress(4),

  /// Double arrow pointing northwest and southeast.
  systemCursorNwseResize(5),

  /// Double arrow pointing northeast and southwest.
  systemCursorNeswResize(6),

  /// Double arrow pointing west and east.
  systemCursorEwResize(7),

  /// Double arrow pointing north and south.
  systemCursorNsResize(8),

  /// Four pointed arrow pointing north, south, east, and west.
  systemCursorMove(9),

  /// Not permitted. Usually a slashed circle or crossbones.
  systemCursorNotAllowed(10),

  /// Pointer that indicates a link. Usually a pointing hand.
  systemCursorPointer(11),

  /// Window resize top-left. This may be a single arrow or a double arrow like
  /// NWSE_RESIZE.
  systemCursorNwResize(12),

  /// Window resize top. May be NS_RESIZE.
  systemCursorNResize(13),

  /// Window resize top-right. May be NESW_RESIZE.
  systemCursorNeResize(14),

  /// Window resize right. May be EW_RESIZE.
  systemCursorEResize(15),

  /// Window resize bottom-right. May be NWSE_RESIZE.
  systemCursorSeResize(16),

  /// Window resize bottom. May be NS_RESIZE.
  systemCursorSResize(17),

  /// Window resize bottom-left. May be NESW_RESIZE.
  systemCursorSwResize(18),

  /// Window resize left. May be EW_RESIZE.
  systemCursorWResize(19),

  /// A context menu is available for the object under the cursor.
  systemCursorContextMenu(20),

  /// Help is available for the object under the cursor.
  systemCursorHelp(21),

  /// A set of cells may be selected.
  systemCursorCell(22),

  /// Text selection. May be TEXT
  systemCursorVerticalText(23),

  /// A shortcut is to be created.
  systemCursorAlias(24),

  /// Something is to be copied.
  systemCursorCopy(25),

  /// The dragged item cannot be dropped at this location. May be NOT_ALLOWED.
  systemCursorNoDrop(26),

  /// The object under the cursor can be grabbed
  systemCursorGrab(27),

  /// An object is currently being grabbed.
  systemCursorGrabbing(28),

  /// Column resize. May be EW_RESIZE.
  systemCursorColResize(29),

  /// Row resize. May be NS_RESIZE.
  systemCursorRowResize(30),

  /// Four pointed arrow pointing north, south, east, and west.
  systemCursorAllScroll(31),

  /// Zoom in.
  systemCursorZoomIn(32),

  /// Zoom out.
  systemCursorZoomOut(33),
  systemCursorCount(34);

  final int value;
  const SDLSystemCursor(this.value);

  static SDLSystemCursor fromValue(int value) => switch (value) {
    0 => systemCursorDefault,
    1 => systemCursorText,
    2 => systemCursorWait,
    3 => systemCursorCrosshair,
    4 => systemCursorProgress,
    5 => systemCursorNwseResize,
    6 => systemCursorNeswResize,
    7 => systemCursorEwResize,
    8 => systemCursorNsResize,
    9 => systemCursorMove,
    10 => systemCursorNotAllowed,
    11 => systemCursorPointer,
    12 => systemCursorNwResize,
    13 => systemCursorNResize,
    14 => systemCursorNeResize,
    15 => systemCursorEResize,
    16 => systemCursorSeResize,
    17 => systemCursorSResize,
    18 => systemCursorSwResize,
    19 => systemCursorWResize,
    20 => systemCursorContextMenu,
    21 => systemCursorHelp,
    22 => systemCursorCell,
    23 => systemCursorVerticalText,
    24 => systemCursorAlias,
    25 => systemCursorCopy,
    26 => systemCursorNoDrop,
    27 => systemCursorGrab,
    28 => systemCursorGrabbing,
    29 => systemCursorColResize,
    30 => systemCursorRowResize,
    31 => systemCursorAllScroll,
    32 => systemCursorZoomIn,
    33 => systemCursorZoomOut,
    34 => systemCursorCount,
    _ => throw ArgumentError('Unknown value for SDLSystemCursor: $value'),
