/// An enum that describes the type of a touch device.
enum SDLTouchDeviceType {
  touchDeviceInvalid(-1),

  /// touch screen with window-relative coordinates
  touchDeviceDirect(0),

  /// trackpad with absolute device coordinates
  touchDeviceIndirectAbsolute(1),

  /// trackpad with screen cursor-relative coordinates
  touchDeviceIndirectRelative(2);

  final int value;
  const SDLTouchDeviceType(this.value);

  static SDLTouchDeviceType fromValue(int value) => switch (value) {
    -1 => touchDeviceInvalid,
    0 => touchDeviceDirect,
    1 => touchDeviceIndirectAbsolute,
    2 => touchDeviceIndirectRelative,
    _ => throw ArgumentError('Unknown value for SDLTouchDeviceType: $value'),
  };
}

/// Data about a single finger in a multitouch event.
final class SDLFinger extends ffi.Struct {
  /// the finger ID
  @ffi.Uint64()
  external int id;

  /// the x-axis location of the touch event, normalized (0...1)
  @ffi.Float()
  external double x;

  /// the y-axis location of the touch event, normalized (0...1)
  @ffi.Float()
  external double y;

  /// the quantity of pressure applied, normalized (0...1)
  @ffi.Float()
  external double pressure;
}

/// Pen axis indices.
enum SDLPenAxis {
  /// Pen pressure. Unidirectional: 0 to 1.0
  penAxisPressure(0),

  /// Pen horizontal tilt angle. Bidirectional: -90.0 to 90.0 (left-to-right).
  penAxisXtilt(1),

  /// Pen vertical tilt angle. Bidirectional: -90.0 to 90.0 (top-to-down).
  penAxisYtilt(2),

  /// Pen distance to drawing surface. Unidirectional: 0.0 to 1.0
  penAxisDistance(3),

  /// Pen barrel rotation. Bidirectional: -180 to 179.9 (clockwise, 0 is facing
  /// up, -180.0 is facing down).
  penAxisRotation(4),

  /// Pen finger wheel or slider (e.g., Airbrush Pen). Unidirectional: 0 to 1.0
  penAxisSlider(5),

  /// Pressure from squeezing the pen ("barrel pressure").
  penAxisTangentialPressure(6),

  /// Total known pen axis types in this version of SDL. This number may grow in
  /// future releases!
  penAxisCount(7);

  final int value;
  const SDLPenAxis(this.value);

  static SDLPenAxis fromValue(int value) => switch (value) {
    0 => penAxisPressure,
    1 => penAxisXtilt,
    2 => penAxisYtilt,
    3 => penAxisDistance,
    4 => penAxisRotation,
    5 => penAxisSlider,
    6 => penAxisTangentialPressure,
    7 => penAxisCount,
    _ => throw ArgumentError('Unknown value for SDLPenAxis: $value'),
  };
}

