    2 => penDeviceTypeIndirect,
    _ => throw ArgumentError('Unknown value for SDLPenDeviceType: $value'),
  };
}

/// The types of events that can be delivered.
sealed class SDLEventType {
  /// Unused (do not remove)
  static const eventFirst = 0;

  /// User-requested quit
  static const eventQuit = 256;

  /// The application is being terminated by the OS. This event must be handled
  /// in a callback set with SDL_AddEventWatch(). Called on iOS in
  /// applicationWillTerminate() Called on Android in onDestroy()
  static const eventTerminating = 257;

  /// The application is low on memory, free memory if possible. This event must
  /// be handled in a callback set with SDL_AddEventWatch(). Called on iOS in
  /// applicationDidReceiveMemoryWarning() Called on Android in onTrimMemory()
  static const eventLowMemory = 258;

  /// The application is about to enter the background. This event must be
  /// handled in a callback set with SDL_AddEventWatch(). Called on iOS in
  /// applicationWillResignActive() Called on Android in onPause()
  static const eventWillEnterBackground = 259;

  /// The application did enter the background and may not get CPU for some
  /// time. This event must be handled in a callback set with
  /// SDL_AddEventWatch(). Called on iOS in applicationDidEnterBackground()
