/// The type of action to request from SDL_PeepEvents().
enum SDLEventAction {
  /// Add events to the back of the queue.
  addevent(0),

  /// Check but don't remove events from the queue front.
  peekevent(1),

  /// Retrieve/remove events from the front of the queue.
  getevent(2);

  final int value;
  const SDLEventAction(this.value);

  static SDLEventAction fromValue(int value) => switch (value) {
    0 => addevent,
    1 => peekevent,
    2 => getevent,
    _ => throw ArgumentError('Unknown value for SDLEventAction: $value'),
  };
}

/// The type of the OS-provided default folder for a specific purpose.
enum SDLFolder {
  /// The folder which contains all of the current user's data, preferences, and
  /// documents. It usually contains most of the other folders. If a requested
  /// folder does not exist, the home folder can be considered a safe fallback
  /// to store a user's documents.
  folderHome(0),

  /// The folder of files that are displayed on the desktop. Note that the
  /// existence of a desktop folder does not guarantee that the system does show
  /// icons on its desktop; certain GNU/Linux distros with a graphical
  /// environment may not have desktop icons.
  folderDesktop(1),

  /// User document files, possibly application-specific. This is a good place
  /// to save a user's projects.
  folderDocuments(2),

  /// Standard folder for user files downloaded from the internet.
  folderDownloads(3),

  /// Music files that can be played using a standard music player (mp3,
  /// ogg...).
  folderMusic(4),

  /// Image files that can be displayed using a standard viewer (png, jpg...).
  folderPictures(5),

  /// Files that are meant to be shared with other users on the same computer.
  folderPublicshare(6),

  /// Save files for games.
  folderSavedgames(7),

  /// Application screenshots.
  folderScreenshots(8),

  /// Template files to be used when the user requests the desktop environment
  /// to create a new file in a certain folder, such as "New Text File.txt". Any
  /// file in the Templates folder can be used as a starting point for a new
  /// file.
  folderTemplates(9),

  /// Video files that can be played using a standard video player (mp4,
  /// webm...).
  folderVideos(10),

  /// Total number of types in this enum, not a folder type by itself.
  folderCount(11);

  final int value;
  const SDLFolder(this.value);

  static SDLFolder fromValue(int value) => switch (value) {
    0 => folderHome,
    1 => folderDesktop,
    2 => folderDocuments,
    3 => folderDownloads,
    4 => folderMusic,
    5 => folderPictures,
    6 => folderPublicshare,
    7 => folderSavedgames,
    8 => folderScreenshots,
    9 => folderTemplates,
    10 => folderVideos,
    11 => folderCount,
    _ => throw ArgumentError('Unknown value for SDLFolder: $value'),
  };
}

/// Types of filesystem entries.
