  static SDLPathType fromValue(int value) => switch (value) {
    0 => pathtypeNone,
    1 => pathtypeFile,
    2 => pathtypeDirectory,
    3 => pathtypeOther,
    _ => throw ArgumentError('Unknown value for SDLPathType: $value'),
  };
}

