/// Application sandbox environment.
enum SDLSandbox {
  sandboxNone(0),
  sandboxUnknownContainer(1),
  sandboxFlatpak(2),
  sandboxSnap(3),
  sandboxMacos(4);

  final int value;
  const SDLSandbox(this.value);

  static SDLSandbox fromValue(int value) => switch (value) {
    0 => sandboxNone,
    1 => sandboxUnknownContainer,
    2 => sandboxFlatpak,
    3 => sandboxSnap,
    4 => sandboxMacos,
    _ => throw ArgumentError('Unknown value for SDLSandbox: $value'),
  };
}

/// A structure holding a calendar date and time broken down into its
/// components.
final class SDLDateTime extends ffi.Struct {
  /// Year
  @ffi.Int()
  external int year;

  /// Month [01-12]
  @ffi.Int()
  external int month;

  /// Day of the month [01-31]
  @ffi.Int()
  external int day;

  /// Hour [0-23]
  @ffi.Int()
  external int hour;

  /// Minute [0-59]
  @ffi.Int()
  external int minute;

  /// Seconds [0-60]
  @ffi.Int()
  external int second;

  /// Nanoseconds [0-999999999]
  @ffi.Int()
  external int nanosecond;

  /// Day of the week [0-6] (0 being Sunday)
  @ffi.Int()
  external int day_of_week;

  /// Seconds east of UTC
  @ffi.Int()
  external int utc_offset;
}

/// The preferred date format of the current system locale.
enum SDLDateFormat {
  /// Year/Month/Day
  dateFormatYyyymmdd(0),

  /// Day/Month/Year
  dateFormatDdmmyyyy(1),

  /// Month/Day/Year
  dateFormatMmddyyyy(2);

  final int value;
  const SDLDateFormat(this.value);

  static SDLDateFormat fromValue(int value) => switch (value) {
    0 => dateFormatYyyymmdd,
    1 => dateFormatDdmmyyyy,
    2 => dateFormatMmddyyyy,
    _ => throw ArgumentError('Unknown value for SDLDateFormat: $value'),
  };
}

/// The preferred time format of the current system locale.
enum SDLTimeFormat {
  /// 24 hour time
  timeFormat24hr(0),

  /// 12 hour time
  timeFormat12hr(1);

  final int value;
  const SDLTimeFormat(this.value);

  static SDLTimeFormat fromValue(int value) => switch (value) {
    0 => timeFormat24hr,
    1 => timeFormat12hr,
    _ => throw ArgumentError('Unknown value for SDLTimeFormat: $value'),
  };
}

